\documentclass{article}
\usepackage{tikz}

% Define a function to convert FEN to coordinates on a 8x8 grid
\newcommand{\fenToGrid}[1]{%
    \begin{scope}[xscale=1/8,yscale=-1/8]
        % Convert rows from 0-7 (FEN's row starts at 1)
        \foreach \i in {0,...,-7}{
            \draw (\i*2+1, -\i) -- ++(0.5,0.5);
        }
        % Convert columns from A-H (FEN's column starts at 'A')
        \foreach \j in {A,B,C,D,E,F,G,H}{
            \node[anchor=north] at (-(-\j)*2-0.5, 0.5*\j) {\j};
        }
        % Draw the pieces
        #1
    \end{scope}%
}

